_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUvOriginal;
uv1 = (vUv-.5) * uAspect.xy;

//BACKGROUND
float z = 16*length(uv1*5)+uTime;
vec2 uvn =normalize(uv1);
rs = clamp(tan(z)*uvn,-5,5)/2;

//CRYSTAL
float mult = q31*4;
uv7 = sin(uv1*mult);
uv8 = uv7;
float dist = length(uv8);
dist *= (abs(uv1.x) + abs(uv1.y))+ q32;

float ang2 = atan(uv8.y,uv8.x);
ang2 =  1*floor(1* ang2);
vec2 dir = .095*uv8+vec2 (cos(ang2), sin(ang2));

z = (1-cos(8*dist));
z *= .200*clamp01(lum(z));

//ADD
float mask = (z <= 1); //momentan beliebig
rs = q28*rs + (1-q28)*rs.yx;
vUv += (1-mask)*3*(rs.yx) + .5*mask*z*normalize(z.x);

//ZENTRALSTRAHL
uv6 = multiply(uv1*.8,mat2(_qb*.150));
mus = .3*abs(0.0225/(sqrt(uv6.x))/uv1.x)*(.5);

//DOTS
vec2 uv2 = 10*uv1+.3*sin(uv1*16+4*vec2 (q5,q6));
uv2 *= 3;
vec3 dots = q26*clamp01(.00065/(length(uv2)));
vec3 blur = GetBlur1(fract(vUv));
vec3 crisp= GetPixel(vUv);
vec3 diff = (crisp) - .5*blur;
vec3 ret1 = crisp + mus + dots;

vec3 mod = texture(sampler_noise_lq,50*vUv+uTime*.1)-.25;
mod = .98 - mod*diff;

ret = (1-mask)*ret1*mod + mask*ret1*mod;
ret *= vec3(.89,.96,.965)+.05*texture(sampler_noise_lq,vUv);
ret *= 2*vec3(.92,.835,.84)*lum(vUvOriginal);

ret *= .98- .1;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


float var1=sin((uTime+(audioLowSmooth-(audioMid*.9)/6)));
float var2=sin((uTime+(audioMidSmooth-(audioHigh*.9)/6)));
float var3=cos((uTime+(audioHighSmooth-(audioLow*.9)/6)));

vec2 uv1 = vUv-.5;

vec3 ret1 = texture(sampler_main, vUv) * (1-vRadius);


vec2 hor = vec2 (uTexSize.z,0)*1-.1*var2;
vec2 ver = vec2 (0,uTexSize.w)*1-.1*var1;
float dx = GetBlur1 (vUv-hor) - GetBlur2 (vUv+hor);
float dy = GetBlur2 (vUv-ver) - GetBlur1 (vUv+ver);
vec2 dz = vec2 (dx,dy)*1.5+.31*var3;

uv1 = uv1*0+.3*cos(uv1*2) - dz;;
float dots = clamp01(.09/length(uv1));
uv1 = uv1*0+.3*cos(uv1*12) - 9*dz;;
vec3 dots2 = clamp01(.09/length(uv1));


ret = (-ret1) + dots + .0 + 12*dots2*(-0+sqrt(ret1));

  fragColor = ret;
}
